import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.BiT4WeDN.js";const m=JSON.parse('{"title":"Tutorials","description":"Step-by-step guided labs for learning Yeast","frontmatter":{"title":"Tutorials","description":"Step-by-step guided labs for learning Yeast"},"headers":[],"relativePath":"docs/tutorials/index.md","filePath":"docs/tutorials/index.md"}'),i={name:"docs/tutorials/index.md"};function o(l,t,s,n,h,u){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="tutorials" tabindex="-1">Tutorials <a class="header-anchor" href="#tutorials" aria-label="Permalink to &quot;Tutorials&quot;">​</a></h1><p>Welcome to the Yeast tutorials! These hands-on labs will teach you how to use Yeast step by step.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before starting the tutorials, make sure you have:</p><ul><li>Yeast installed (<code>yeast --version</code>)</li><li>KVM support enabled (<code>yeast doctor</code>)</li><li>SSH key configured</li><li>Basic command line knowledge</li></ul><h2 id="tutorial-map" tabindex="-1">Tutorial Map <a class="header-anchor" href="#tutorial-map" aria-label="Permalink to &quot;Tutorial Map&quot;">​</a></h2><h3 id="fundamentals" tabindex="-1">Fundamentals <a class="header-anchor" href="#fundamentals" aria-label="Permalink to &quot;Fundamentals&quot;">​</a></h3><p>Start here to learn the basics:</p><table tabindex="0"><thead><tr><th>#</th><th>Tutorial</th><th>Difficulty</th><th>Time</th><th>What You&#39;ll Learn</th></tr></thead><tbody><tr><td>01</td><td><a href="./01-first-vm.html">First VM</a></td><td>Beginner</td><td>15 min</td><td>Create, start, SSH, stop, destroy</td></tr><tr><td>02</td><td><a href="./02-provisioning.html">Provisioning</a></td><td>Beginner</td><td>20 min</td><td>Install packages, copy files, run commands</td></tr><tr><td>03</td><td><a href="./03-snapshots.html">Snapshots</a></td><td>Beginner</td><td>20 min</td><td>Take and restore snapshots</td></tr><tr><td>04</td><td><a href="./04-multi-vm-lab.html">Multi-VM Lab</a></td><td>Intermediate</td><td>30 min</td><td>Multiple VMs with private networking</td></tr></tbody></table><h3 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h3><p>Build on the fundamentals:</p><table tabindex="0"><thead><tr><th>#</th><th>Tutorial</th><th>Difficulty</th><th>Time</th><th>What You&#39;ll Learn</th></tr></thead><tbody><tr><td>05</td><td><a href="./05-guest-control.html">Guest Control</a></td><td>Intermediate</td><td>20 min</td><td>exec, copy, logs, inspect</td></tr><tr><td>06</td><td><a href="./06-labsbackery-lab.html">LabsBackery Lab</a></td><td>Intermediate</td><td>45 min</td><td>Cybersecurity lab environment</td></tr><tr><td>07</td><td><a href="./07-templates.html">Templates</a></td><td>Intermediate</td><td>25 min</td><td>Built-in and custom templates</td></tr><tr><td>08</td><td><a href="./08-json-automation.html">JSON Automation</a></td><td>Intermediate</td><td>30 min</td><td>JSON output and event streams</td></tr></tbody></table><h3 id="project-labs" tabindex="-1">Project Labs <a class="header-anchor" href="#project-labs" aria-label="Permalink to &quot;Project Labs&quot;">​</a></h3><p>Complex, real-world projects:</p><table tabindex="0"><thead><tr><th>#</th><th>Tutorial</th><th>Difficulty</th><th>Time</th><th>What You&#39;ll Learn</th></tr></thead><tbody><tr><td>09</td><td><a href="./09-nodi-home-lab.html">Nodi Home Lab</a></td><td>Advanced</td><td>60 min</td><td>4-VM service architecture</td></tr><tr><td>10</td><td><a href="./10-load-balancer-lab.html">Load Balancer</a></td><td>Advanced</td><td>45 min</td><td>Caddy reverse proxy</td></tr><tr><td>11</td><td><a href="./11-database-app-stack.html">Database + App</a></td><td>Advanced</td><td>50 min</td><td>PostgreSQL + Node.js API</td></tr><tr><td>12</td><td><a href="./12-monitoring-stack.html">Monitoring Stack</a></td><td>Advanced</td><td>50 min</td><td>Prometheus + Grafana</td></tr><tr><td>13</td><td><a href="./13-wireguard-vpn-mesh.html">WireGuard VPN</a></td><td>Advanced</td><td>50 min</td><td>Encrypted VPN tunnels</td></tr><tr><td>14</td><td><a href="./14-gitops-ci-lab.html">GitOps/CI</a></td><td>Advanced</td><td>50 min</td><td>Gitea + Drone CI pipeline</td></tr></tbody></table><h2 id="how-to-use-tutorials" tabindex="-1">How to Use Tutorials <a class="header-anchor" href="#how-to-use-tutorials" aria-label="Permalink to &quot;How to Use Tutorials&quot;">​</a></h2><ol><li><strong>Start with Fundamentals</strong> - Complete tutorials 01-04 first</li><li><strong>Follow the Steps</strong> - Each tutorial has step-by-step instructions</li><li><strong>Run the Code</strong> - Type the commands yourself</li><li><strong>Experiment</strong> - Try modifying the examples</li><li><strong>Check Your Understanding</strong> - Review the &quot;What You Learned&quot; section</li></ol><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><p>If you get stuck:</p><ul><li>Check the <a href="/yeast/docs/troubleshooting.html">Troubleshooting</a> page</li><li>Look at the &quot;Common Failures&quot; section in each tutorial</li><li>Search <a href="https://github.com/Twarga/yeast/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Start with <a href="./01-first-vm.html">Tutorial 01: First VM</a> to begin your Yeast journey!</p>',22)])])}const p=e(i,[["render",o]]);export{m as __pageData,p as default};
